# variables.tf
variable "subscriptions" {
  description = "Map of subscription definitions to provision"
  type = map(object({
    display_name     = string
    billing_scope_id = string
    strategy_tier    = string # single | corp-prod | corp-nonprod | online | sandbox
    workload_type    = string # Production | DevTest
    tags             = map(string)
  }))
}

variable "management_group_ids" {
  type = map(string)
  description = "Map from strategy_tier to management group resource ID"
  # e.g. { corp-prod = "/providers/Microsoft.Management/managementGroups/mg-corp-prod" }
}

# main.tf
resource "azurerm_subscription" "this" {
  for_each          = var.subscriptions
  subscription_name = each.value.display_name
  billing_scope_id  = each.value.billing_scope_id
  workload          = each.value.workload_type
  tags              = each.value.tags
}

resource "azurerm_management_group_subscription_association" "this" {
  for_each            = var.subscriptions
  management_group_id = var.management_group_ids[each.value.strategy_tier]
  subscription_id     = azurerm_subscription.this[each.key].id
  depends_on          = [azurerm_subscription.this]
}

# outputs.tf
output "subscription_ids" {
  value = { for k, v in azurerm_subscription.this : k => v.subscription_id }
}

# terraform.tfvars example — per-workload strategy
subscriptions = {
  payments-prod = {
    display_name     = "Payments-Production"
    billing_scope_id = "/providers/Microsoft.Billing/billingAccounts/123456/enrollmentAccounts/789"
    strategy_tier    = "corp-prod"
    workload_type    = "Production"
    tags = {
      environment   = "production"
      workload      = "payments"
      cost-center   = "CC-1001"
    }
  }
  payments-nonprod = {
    display_name     = "Payments-NonProd"
    billing_scope_id = "/providers/Microsoft.Billing/billingAccounts/123456/enrollmentAccounts/789"
    strategy_tier    = "corp-nonprod"
    workload_type    = "DevTest"
    tags = {
      environment   = "development"
      workload      = "payments"
      cost-center   = "CC-1001"
    }
  }
  ecommerce-prod = {
    display_name     = "Ecommerce-Production"
    billing_scope_id = "/providers/Microsoft.Billing/billingAccounts/123456/enrollmentAccounts/789"
    strategy_tier    = "corp-prod"
    workload_type    = "Production"
    tags = {
      environment   = "production"
      workload      = "ecommerce"
      cost-center   = "CC-2002"
    }
  }
}
